from langchain.agents.agent import AgentOutputParser
from langchain.agents.chat.prompt import FORMAT_INSTRUCTIONS
from langchain.schema import AgentAction, AgentFinish, OutputParserException

FINAL_ANSWER_ACTION = "Final Answer:"
FINAL_ANSWER_AND_PARSABLE_ACTION_ERROR_MESSAGE = (
    "Parsing LLM output produced both a final answer and a parse-able action:"
)
FINAL_ANSWER_AND_PARSABLE_ACTION_OBSERVATION = (
    "Invalid Format: Output contains both a final answer and a parse-able action."
)


class ChatOutputParser(AgentOutputParser):
    def get_format_instructions(self) -> str:
        return FORMAT_INSTRUCTIONS

    def parse(self, text: str) -> Union[AgentAction, AgentFinish]:
        includes_final_answer = FINAL_ANSWER_ACTION in re.sub(
            r"```[\s\S]*?```", "", text
        )
        try:
            action = text.split("```")[1]
            response = json.loads(action.strip())
        except Exception:
            if includes_final_answer:
                return AgentFinish(
                    {"output": text.split(FINAL_ANSWER_ACTION)[-1].strip()}, text
                )
            raise OutputParserException(f"Could not parse LLM output: {text}")

        if includes_final_answer:
            raise OutputParserException(
                f"{FINAL_ANSWER_AND_PARSABLE_ACTION_ERROR_MESSAGE} {text}",
                observation=FINAL_ANSWER_AND_PARSABLE_ACTION_OBSERVATION,
                llm_output=text,
                send_to_llm=True,
            )

        return AgentAction(response["action"], response["action_input"], text)

    @property
    def _type(self) -> str:
        return "chat"

